import React, {useState} from "react";

import IndexHeader from "./IndexHeader/IndexHeader";
import FullPageVideo from "./FullPageVideo/FullPageVideo";
import About from "./About/About";
import CourseList from "./CourseList/CourseList";
import Questions from "./Questions/Questions";
import Footer from "../../multComponents/Footer/Footer";

const IndexPage = () => {

  const [entryModalActive, setEntryModalActive] = useState(false);
  return(
    <section>
      <IndexHeader entryModalActive={entryModalActive} setEntryModalActive={setEntryModalActive}/>
      <FullPageVideo />
      <About />
      <CourseList />
      <Questions />
      <Footer />
    </section>
  );
}

export default IndexPage;
